mapper.update:
UPDATE trip_block
SET transit_duration_minutes = #{transitDurationMinutes},
    transit_mode             = #{transitMode},
    transit_option_index     = #{transitOptionIndex}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM trip_block tb
JOIN trip_candidate tc ON tc.id = tb.candidate_id
WHERE tc.trip_id = #{tripId}
  AND tb.trip_date = #{date}
  AND tb.start_time IS NOT NULL
  AND tb.id <> #{excludeBlockId}
  AND (TIME_TO_SEC(tb.start_time) / 60) < #{endMin}
  AND #{startMin} < (TIME_TO_SEC(tb.start_time) / 60 + tb.duration_minutes)

SELECT tb.*
FROM trip_block tb
JOIN trip_candidate tc ON tc.id = tb.candidate_id
WHERE tc.trip_id = #{tripId}
  AND tb.trip_date = #{date}
ORDER BY tb.display_order

mapper.delete:
DELETE FROM trip_block
WHERE candidate_id IN (
    SELECT id FROM trip_candidate WHERE trip_id = #{tripId}
)
